sql:
SELECT MAX(churn_probability) AS highest_churn_probability
FROM churn_predictions
WHERE churn_probability > 0.8;

SELECT churn_probability
FROM churn_predictions
WHERE customer_id = 0;

SELECT customer_id, SUM(usage_price) AS total_usage_price
FROM service_usage
GROUP BY customer_id;

SELECT COUNT(*) 
FROM service_usage 
WHERE customer_id = 0 AND usage_type = 'voice';

external_knowledge:
- 'teetering on the edge' refers to customers with active services and a high or medium churn severity, as well as a churn probability greater than 0.5; 
- 'average outstanding balances' refers to the average total amount due for the invoice; 
- 'highest likelihood of leaving' refers to the maximum churn probability; 
- 'substantial risk of churning' refers to churn probability greater than 0.5 and churn severity of 'medium' or 'high'.
